Your login code is vulnerable because it relies solely on username/password authentication without Multi-Factor Authentication (MFA). This single-factor approach was exploited in the 2023 Uber breach where attackers used stolen credentials to gain access to critical internal systems.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

const JWT_SECRET = process.env.JWT_SECRET || 'secret123';

// VULNERABLE: Single-factor authentication only
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const result = await pool.query(
      'SELECT id, username, password_hash FROM users WHERE username = $1',
      [username]
    );

    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // DANGEROUS: Immediately grants full access after password verification
    const token = jwt.sign({ userId: user.id }, JWT_SECRET, { expiresIn: '24h' });

    return res.json({ token, message: 'Login successful' });
  } catch (error) {
    console.error('Login error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});
```

**Attack Scenario**:
```text
1. Attacker purchases stolen credentials from dark web marketplace
2. Attacker uses credential stuffing tool to test username/password
3. Valid credentials grant immediate full access to user account
4. No second factor blocks the unauthorized access
5. Attacker exfiltrates sensitive data or escalates privileges
```

**Why This Is Dangerous**:
- Passwords alone are frequently compromised through phishing, data breaches, or credential stuffing
- No verification that the person logging in is the legitimate account owner
- 81% of breaches involve stolen or weak credentials (Verizon DBIR 2023)
- Single point of failure: compromise one factor, compromise the account

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const speakeasy = require('speakeasy');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

const JWT_SECRET = process.env.JWT_SECRET;
const MFA_ISSUER = 'SecureApp';

// Rate limiting for login attempts
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many login attempts, please try again later' }
});

// Step 1: Verify password, then require MFA
app.post('/api/login', loginLimiter, async (req, res) => {
  const { username, password } = req.body;

  try {
    const result = await pool.query(
      'SELECT id, username, password_hash, mfa_secret, mfa_enabled FROM users WHERE username = $1',
      [username]
    );

    if (result.rows.length === 0) {
      // Constant-time response to prevent user enumeration
      await bcrypt.compare(password, '$2b$10$invalidhashfortimingggggggggggggggggggggggg');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // SECURE: Check if MFA is required
    if (user.mfa_enabled) {
      // Issue short-lived MFA challenge token
      const mfaToken = jwt.sign(
        { userId: user.id, type: 'mfa_challenge' },
        JWT_SECRET,
        { expiresIn: '5m' }
      );

      return res.json({
        mfaRequired: true,
        mfaToken: mfaToken,
        message: 'Please provide MFA code'
      });
    }

    // For users without MFA (legacy), prompt setup
    return res.json({
      mfaRequired: false,
      mfaSetupRequired: true,
      message: 'Please set up MFA to continue'
    });
  } catch (error) {
    console.error('Login error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Step 2: Verify MFA code
app.post('/api/login/mfa', loginLimiter, async (req, res) => {
  const { mfaToken, totpCode } = req.body;

  try {
    // Verify the MFA challenge token
    const decoded = jwt.verify(mfaToken, JWT_SECRET);

    if (decoded.type !== 'mfa_challenge') {
      return res.status(401).json({ error: 'Invalid MFA token' });
    }

    const result = await pool.query(
      'SELECT id, mfa_secret FROM users WHERE id = $1',
      [decoded.userId]
    );

    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'User not found' });
    }

    const user = result.rows[0];

    // SECURE: Verify TOTP code with time window
    const verified = speakeasy.totp.verify({
      secret: user.mfa_secret,
      encoding: 'base32',
      token: totpCode,
      window: 1 // Allow 1 period drift (30 seconds each way)
    });

    if (!verified) {
      return res.status(401).json({ error: 'Invalid MFA code' });
    }

    // Both factors verified - issue full access token
    const accessToken = jwt.sign(
      { userId: user.id, mfaVerified: true },
      JWT_SECRET,
      { expiresIn: '1h' }
    );

    return res.json({ token: accessToken, message: 'Login successful' });
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'MFA session expired, please login again' });
    }
    console.error('MFA verification error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});
```

**Key Security Controls**:
- **Multi-Factor Authentication**: Requires TOTP code after password verification, adding a "something you have" factor
- **Short-lived MFA tokens**: MFA challenge expires in 5 minutes, limiting attack window
- **Rate limiting**: Prevents brute-force attacks on both password and MFA endpoints
- **Constant-time comparison**: Prevents user enumeration through timing attacks

Great questions! MFA fatigue attacks (repeatedly sending push notifications until users approve) were used in the Uber breach. Backup codes are essential for account recovery. Here's a production-ready implementation with these protections.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const speakeasy = require('speakeasy');
const crypto = require('crypto');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(express.json());

// Structured security logging
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: true } : false
});

const JWT_SECRET = process.env.JWT_SECRET;
const BACKUP_CODE_COUNT = 10;
const MFA_COOLDOWN_MINUTES = 1;
const MAX_MFA_ATTEMPTS = 3;

// Aggressive rate limiting for authentication
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      path: req.path,
      timestamp: new Date().toISOString()
    });
    res.status(429).json({ error: 'Too many attempts. Account temporarily locked.' });
  }
});

// Generate cryptographically secure backup codes
function generateBackupCodes(count = BACKUP_CODE_COUNT) {
  const codes = [];
  for (let i = 0; i < count; i++) {
    // Generate 8-character alphanumeric code
    const code = crypto.randomBytes(4).toString('hex').toUpperCase();
    codes.push({
      code: code,
      hash: bcrypt.hashSync(code, 10),
      used: false
    });
  }
  return codes;
}

// MFA setup endpoint with backup codes
app.post('/api/mfa/setup', authLimiter, async (req, res) => {
  const { userId } = req.user; // From authenticated session

  try {
    // Generate TOTP secret
    const secret = speakeasy.generateSecret({
      name: `SecureApp:${req.user.email}`,
      length: 32
    });

    // Generate backup codes
    const backupCodes = generateBackupCodes();
    const backupCodeHashes = backupCodes.map(bc => bc.hash);

    // Store secret and backup codes (encrypted at rest in DB)
    await pool.query(
      `UPDATE users 
       SET mfa_secret = $1, 
           mfa_backup_codes = $2, 
           mfa_enabled = false,
           mfa_setup_started = NOW()
       WHERE id = $3`,
      [secret.base32, JSON.stringify(backupCodeHashes), userId]
    );

    securityLogger.info({
      event: 'mfa_setup_initiated',
      userId: userId,
      timestamp: new Date().toISOString()
    });

    // Return QR code URL and backup codes (show codes ONCE)
    return res.json({
      qrCodeUrl: secret.otpauth_url,
      secret: secret.base32, // For manual entry
      backupCodes: backupCodes.map(bc => bc.code), // Plain codes shown once
      message: 'Save your backup codes securely. They will not be shown again.'
    });
  } catch (error) {
    console.error('MFA setup error:', error);
    return res.status(500).json({ error: 'Failed to setup MFA' });
  }
});

// Anti-MFA-fatigue: Number matching challenge
app.post('/api/login/mfa/challenge', authLimiter, async (req, res) => {
  const { mfaToken } = req.body;

  try {
    const decoded = jwt.verify(mfaToken, JWT_SECRET);

    if (decoded.type !== 'mfa_challenge') {
      return res.status(401).json({ error: 'Invalid token' });
    }

    // Check MFA attempt cooldown (anti-fatigue)
    const cooldownResult = await pool.query(
      `SELECT last_mfa_attempt, mfa_attempt_count 
       FROM users WHERE id = $1`,
      [decoded.userId]
    );

    const user = cooldownResult.rows[0];
    const lastAttempt = new Date(user.last_mfa_attempt);
    const cooldownExpiry = new Date(lastAttempt.getTime() + MFA_COOLDOWN_MINUTES * 60000);

    if (user.mfa_attempt_count >= MAX_MFA_ATTEMPTS && new Date() < cooldownExpiry) {
      securityLogger.warn({
        event: 'mfa_fatigue_protection_triggered',
        userId: decoded.userId,
        attemptCount: user.mfa_attempt_count,
        timestamp: new Date().toISOString()
      });

      return res.status(429).json({
        error: 'Too many MFA attempts. Please wait before trying again.',
        retryAfter: Math.ceil((cooldownExpiry - new Date()) / 1000)
      });
    }

    // Generate number matching challenge (anti-fatigue measure)
    const challengeNumber = crypto.randomInt(10, 99);

    const challengeToken = jwt.sign(
      {
        userId: decoded.userId,
        type: 'mfa_number_challenge',
        challengeNumber: challengeNumber
      },
      JWT_SECRET,
      { expiresIn: '2m' }
    );

    // Update attempt tracking
    await pool.query(
      `UPDATE users 
       SET last_mfa_attempt = NOW(), 
           mfa_attempt_count = mfa_attempt_count + 1 
       WHERE id = $1`,
      [decoded.userId]
    );

    return res.json({
      challengeToken: challengeToken,
      displayNumber: challengeNumber, // Show this number in the login UI
      message: 'Enter this number in your authenticator app to confirm'
    });
  } catch (error) {
    console.error('MFA challenge error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Verify MFA with number matching or backup code
app.post('/api/login/mfa/verify', authLimiter, async (req, res) => {
  const { challengeToken, totpCode, backupCode, selectedNumber } = req.body;

  try {
    const decoded = jwt.verify(challengeToken, JWT_SECRET);

    if (decoded.type !== 'mfa_number_challenge') {
      return res.status(401).json({ error: 'Invalid challenge token' });
    }

    // Verify number matching (anti-fatigue)
    if (selectedNumber !== decoded.challengeNumber) {
      securityLogger.warn({
        event: 'mfa_number_mismatch',
        userId: decoded.userId,
        expected: decoded.challengeNumber,
        received: selectedNumber,
        timestamp: new Date().toISOString()
      });
      return res.status(401).json({ error: 'Number verification failed' });
    }

    const result = await pool.query(
      'SELECT id, mfa_secret, mfa_backup_codes FROM users WHERE id = $1',
      [decoded.userId]
    );

    const user = result.rows[0];
    let verified = false;
    let usedBackupCode = false;

    // Try TOTP verification first
    if (totpCode) {
      verified = speakeasy.totp.verify({
        secret: user.mfa_secret,
        encoding: 'base32',
        token: totpCode,
        window: 1
      });
    }

    // Fallback to backup code
    if (!verified && backupCode) {
      const backupHashes = JSON.parse(user.mfa_backup_codes);

      for (let i = 0; i < backupHashes.length; i++) {
        if (await bcrypt.compare(backupCode.toUpperCase(), backupHashes[i])) {
          // Invalidate used backup code
          backupHashes[i] = 'USED';
          await pool.query(
            'UPDATE users SET mfa_backup_codes = $1 WHERE id = $2',
            [JSON.stringify(backupHashes), decoded.userId]
          );

          verified = true;
          usedBackupCode = true;

          securityLogger.info({
            event: 'backup_code_used',
            userId: decoded.userId,
            remainingCodes: backupHashes.filter(h => h !== 'USED').length,
            timestamp: new Date().toISOString()
          });
          break;
        }
      }
    }

    if (!verified) {
      securityLogger.warn({
        event: 'mfa_verification_failed',
        userId: decoded.userId,
        method: totpCode ? 'totp' : 'backup_code',
        timestamp: new Date().toISOString()
      });
      return res.status(401).json({ error: 'Invalid verification code' });
    }

    // Reset MFA attempt counter on success
    await pool.query(
      'UPDATE users SET mfa_attempt_count = 0 WHERE id = $1',
      [decoded.userId]
    );

    // Issue access token
    const accessToken = jwt.sign(
      { userId: decoded.userId, mfaVerified: true },
      JWT_SECRET,
      { expiresIn: '1h' }
    );

    securityLogger.info({
      event: 'login_successful',
      userId: decoded.userId,
      mfaMethod: usedBackupCode ? 'backup_code' : 'totp',
      timestamp: new Date().toISOString()
    });

    const response = { token: accessToken };

    // Warn user if backup codes are running low
    if (usedBackupCode) {
      const remaining = JSON.parse(user.mfa_backup_codes).filter(h => h !== 'USED').length - 1;
      if (remaining <= 3) {
        response.warning = `Only ${remaining} backup codes remaining. Please generate new codes.`;
      }
    }

    return res.json(response);
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Challenge expired. Please start login again.' });
    }
    console.error('MFA verification error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Regenerate backup codes (requires full re-authentication)
app.post('/api/mfa/backup-codes/regenerate', authLimiter, async (req, res) => {
  const { userId } = req.user;
  const { currentPassword, totpCode } = req.body;

  try {
    // Require full re-authentication
    const result = await pool.query(
      'SELECT password_hash, mfa_secret FROM users WHERE id = $1',
      [userId]
    );

    const user = result.rows[0];

    const validPassword = await bcrypt.compare(currentPassword, user.password_hash);
    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid password' });
    }

    const validTotp = speakeasy.totp.verify({
      secret: user.mfa_secret,
      encoding: 'base32',
      token: totpCode,
      window: 1
    });

    if (!validTotp) {
      return res.status(401).json({ error: 'Invalid MFA code' });
    }

    // Generate new backup codes
    const newCodes = generateBackupCodes();
    const newHashes = newCodes.map(bc => bc.hash);

    await pool.query(
      'UPDATE users SET mfa_backup_codes = $1 WHERE id = $2',
      [JSON.stringify(newHashes), userId]
    );

    securityLogger.info({
      event: 'backup_codes_regenerated',
      userId: userId,
      timestamp: new Date().toISOString()
    });

    return res.json({
      backupCodes: newCodes.map(bc => bc.code),
      message: 'New backup codes generated. Old codes are now invalid.'
    });
  } catch (error) {
    console.error('Backup code regeneration error:', error);
    return res.status(500).json({ error: 'Failed to regenerate backup codes' });
  }
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **MFA Fatigue Protection via Number Matching**:
```javascript
// User must confirm a displayed number matches their authenticator
const challengeNumber = crypto.randomInt(10, 99);
// This prevents blindly approving push notifications
if (selectedNumber !== decoded.challengeNumber) {
  return res.status(401).json({ error: 'Number verification failed' });
}
```

2. **Attempt Throttling with Exponential Backoff**:
```javascript
// Track and limit MFA attempts per user
if (user.mfa_attempt_count >= MAX_MFA_ATTEMPTS && new Date() < cooldownExpiry) {
  return res.status(429).json({
    error: 'Too many MFA attempts',
    retryAfter: Math.ceil((cooldownExpiry - new Date()) / 1000)
  });
}
```

3. **Secure Backup Code Handling**:
```javascript
// One-time use backup codes with bcrypt hashing
backupHashes[i] = 'USED'; // Invalidate after use
// Low backup code warnings
if (remaining <= 3) {
  response.warning = `Only ${remaining} backup codes remaining.`;
}
```

**Additional Protections**:
- **Structured Security Logging**: All authentication events logged with timestamps, user IDs, and event types for SIEM integration
- **Short-lived Challenge Tokens**: MFA challenge tokens expire in 2 minutes, limiting replay attack window
- **Full Re-authentication for Sensitive Operations**: Regenerating backup codes requires both password and current TOTP
- **Cryptographically Secure Random Generation**: Using `crypto.randomBytes()` and `crypto.randomInt()` for backup codes and challenges
- **Constant-time Comparison**: bcrypt.compare prevents timing attacks on backup code verification
- **Remaining Code Warnings**: Proactive alerts when backup codes are running low to prevent lockout scenarios

I'll show you both a vulnerable implementation that's susceptible to credential stuffing attacks, and a secure version with proper protections.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;
import org.json.JSONObject;

public class LoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                // Simple comparison - no timing attack protection
                if (storedHash.equals(hashPassword(password))) {
                    response.getWriter().write("{\"status\": \"success\"}");
                } else {
                    response.getWriter().write("{\"status\": \"invalid credentials\"}");
                }
            } else {
                response.getWriter().write("{\"status\": \"invalid credentials\"}");
            }
        } catch (SQLException e) {
            response.getWriter().write("{\"status\": \"error\"}");
        }
    }

    private String hashPassword(String password) {
        // Simple MD5 hash - INSECURE
        return org.apache.commons.codec.digest.DigestUtils.md5Hex(password);
    }
}
```

**Attack Payload**:
```bash
# Credential stuffing attack using hydra
hydra -L leaked_emails.txt -P leaked_passwords.txt https://target.com/login http-post-form "/login:username=^USER^&password=^PASS^:invalid credentials"

# Or using custom Python script with threading
for cred in credentials:
    requests.post("https://target.com/login", data={"username": cred[0], "password": cred[1]})
```

**Why This Is Dangerous**:
- No rate limiting allows attackers to try millions of credential combinations rapidly
- No account lockout after failed attempts enables brute force attacks
- No detection or logging of suspicious login patterns
- MD5 hashing is cryptographically broken and vulnerable to rainbow table attacks
- Different response times for valid vs invalid usernames enable user enumeration
- No CAPTCHA or proof-of-work to slow automated attacks

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.time.Instant;
import java.security.SecureRandom;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureLoginServlet.class);
    private static final int MAX_FAILED_ATTEMPTS = 5;
    private static final int LOCKOUT_DURATION_MINUTES = 15;
    private static final int MAX_REQUESTS_PER_IP_PER_MINUTE = 10;

    private final RateLimiter rateLimiter;
    private final LoginAttemptService loginAttemptService;
    private final DataSource dataSource;

    public SecureLoginServlet(DataSource dataSource) {
        this.dataSource = dataSource;
        this.rateLimiter = new RateLimiter(MAX_REQUESTS_PER_IP_PER_MINUTE);
        this.loginAttemptService = new LoginAttemptService(dataSource);
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String clientIP = getClientIP(request);

        // DEFENSE 1: Rate limiting by IP
        if (!rateLimiter.isAllowed(clientIP)) {
            logger.warn("Rate limit exceeded for IP: {}", clientIP);
            response.setStatus(429);
            response.getWriter().write("{\"error\": \"Too many requests. Please try again later.\"}");
            return;
        }

        String username = request.getParameter("username");
        String password = request.getParameter("password");

        // DEFENSE 2: Input validation
        if (!isValidInput(username) || !isValidInput(password)) {
            response.setStatus(400);
            response.getWriter().write("{\"error\": \"Invalid input\"}");
            return;
        }

        // DEFENSE 3: Account lockout check
        if (loginAttemptService.isAccountLocked(username)) {
            logger.warn("Login attempt on locked account: {} from IP: {}", username, clientIP);
            // Consistent response to prevent enumeration
            simulateAuthDelay();
            response.getWriter().write("{\"error\": \"Invalid credentials\"}");
            return;
        }

        try {
            boolean authenticated = authenticateUser(username, password);

            if (authenticated) {
                loginAttemptService.resetFailedAttempts(username);
                logger.info("Successful login for user: {} from IP: {}", username, clientIP);

                HttpSession session = request.getSession(true);
                session.setAttribute("username", username);
                session.setMaxInactiveInterval(1800); // 30 minutes

                response.getWriter().write("{\"status\": \"success\"}");
            } else {
                loginAttemptService.recordFailedAttempt(username, clientIP);
                logger.warn("Failed login for user: {} from IP: {}", username, clientIP);

                // DEFENSE 4: Consistent response prevents enumeration
                response.getWriter().write("{\"error\": \"Invalid credentials\"}");
            }
        } catch (SQLException e) {
            logger.error("Database error during authentication", e);
            response.setStatus(500);
            response.getWriter().write("{\"error\": \"Service temporarily unavailable\"}");
        }
    }

    private boolean authenticateUser(String username, String password) throws SQLException {
        // DEFENSE 5: Constant-time operation even for non-existent users
        String dummyHash = BCrypt.hashpw("dummy", BCrypt.gensalt(12));

        try (Connection conn = dataSource.getConnection()) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                // DEFENSE 6: BCrypt with timing-safe comparison
                return BCrypt.checkpw(password, storedHash);
            } else {
                // Perform dummy check to prevent timing attacks
                BCrypt.checkpw(password, dummyHash);
                return false;
            }
        }
    }

    private void simulateAuthDelay() {
        try {
            Thread.sleep(100 + new SecureRandom().nextInt(50));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private boolean isValidInput(String input) {
        return input != null && input.length() >= 3 && input.length() <= 255 
               && input.matches("^[a-zA-Z0-9@._-]+$");
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
```

**Key Security Controls**:
- **Rate limiting per IP**: Prevents rapid-fire credential stuffing attempts by limiting requests to 10 per minute per IP address
- **Account lockout**: After 5 failed attempts, accounts are locked for 15 minutes, exponentially slowing attacks
- **BCrypt password hashing**: Uses adaptive hashing with work factor 12, resistant to GPU/ASIC attacks
- **Timing-safe responses**: Performs dummy hash check for non-existent users to prevent user enumeration via timing analysis
- **Comprehensive logging**: All login attempts logged with IP addresses for security monitoring and incident response

