```go
package main

import (
	"crypto/rand"
	"database/sql"
	"encoding/base32"
	"encoding/json"
	"log"
	"net/http"
	"time"

	"github.com/pquerna/otp/totp"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type MFAVerifyRequest struct {
	SessionToken string `json:"session_token"`
	TOTPCode     string `json:"totp_code"`
}

type AuthService struct {
	db     *sql.DB
	logger *log.Logger
}

// Step 1: Verify password, return partial session requiring MFA
func (s *AuthService) LoginHandler(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	var storedHash, totpSecret string
	var userID int
	var mfaEnabled bool
	err := s.db.QueryRow(
		"SELECT id, password_hash, totp_secret, mfa_enabled FROM users WHERE username = $1",
		req.Username,
	).Scan(&userID, &storedHash, &totpSecret, &mfaEnabled)

	if err != nil {
		s.logger.Printf("Login failed for username %s: user not found", req.Username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(req.Password)); err != nil {
		s.logger.Printf("Login failed for user %d: invalid password", userID)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// SECURE: Issue partial session token requiring MFA completion
	partialToken := generatePartialSessionToken(userID)
	_, err = s.db.Exec(
		"INSERT INTO pending_mfa_sessions (token, user_id, created_at, expires_at) VALUES ($1, $2, $3, $4)",
		partialToken, userID, time.Now(), time.Now().Add(5*time.Minute),
	)
	if err != nil {
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	s.logger.Printf("Password verified for user %d, awaiting MFA", userID)
	json.NewEncoder(w).Encode(map[string]interface{}{
		"status":        "mfa_required",
		"session_token": partialToken,
		"mfa_enabled":   mfaEnabled,
	})
}

// Step 2: Verify TOTP code to complete authentication
func (s *AuthService) VerifyMFAHandler(w http.ResponseWriter, r *http.Request) {
	var req MFAVerifyRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	var userID int
	var expiresAt time.Time
	err := s.db.QueryRow(
		"SELECT user_id, expires_at FROM pending_mfa_sessions WHERE token = $1",
		req.SessionToken,
	).Scan(&userID, &expiresAt)

	if err != nil || time.Now().After(expiresAt) {
		s.logger.Printf("MFA verification failed: invalid or expired session")
		http.Error(w, "Invalid or expired session", http.StatusUnauthorized)
		return
	}

	var totpSecret string
	s.db.QueryRow("SELECT totp_secret FROM users WHERE id = $1", userID).Scan(&totpSecret)

	// SECURE: Verify TOTP code with time window tolerance
	if !totp.Validate(req.TOTPCode, totpSecret) {
		s.logger.Printf("MFA verification failed for user %d: invalid TOTP", userID)
		http.Error(w, "Invalid MFA code", http.StatusUnauthorized)
		return
	}

	// Delete pending session and issue full access token
	s.db.Exec("DELETE FROM pending_mfa_sessions WHERE token = $1", req.SessionToken)

	fullToken := generateFullSessionToken(userID)
	s.logger.Printf("MFA verified, full session issued for user %d", userID)
	json.NewEncoder(w).Encode(map[string]string{"token": fullToken, "status": "authenticated"})
}
```

**Key Security Controls**:
- **Two-step authentication**: Password verification alone doesn't grant access; MFA completion is mandatory
- **Time-limited partial sessions**: Partial tokens expire in 5 minutes, preventing replay attacks
- **TOTP verification**: Uses RFC 6238 compliant time-based one-time passwords with industry-standard library
- **Audit logging**: All authentication events are logged for security monitoring

Excellent question! The 2023 Uber breach specifically exploited MFA fatigue (repeatedly sending push notifications until user approves). A production-ready MFA system needs rate limiting, multiple MFA methods, secure backup codes, and anti-fatigue protections.

**PRODUCTION PATTERN**:

```go
package main

import (
	"crypto/rand"
	"crypto/sha256"
	"database/sql"
	"encoding/base32"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/pquerna/otp/totp"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type MFAMethod string

const (
	MFATOTP       MFAMethod = "totp"
	MFABackupCode MFAMethod = "backup_code"
	MFAWebAuthn   MFAMethod = "webauthn"
	MFAPush       MFAMethod = "push"
)

type MFAConfig struct {
	MaxPushAttemptsPerHour    int
	MaxTOTPAttemptsPerSession int
	BackupCodeCount           int
	PartialSessionTTL         time.Duration
	PushCooldownPeriod        time.Duration
}

type SecureAuthService struct {
	db         *sql.DB
	logger     *log.Logger
	config     MFAConfig
	rateLimits sync.Map // In production, use Redis
}

type MFAAttempt struct {
	Count     int
	LastReset time.Time
	Locked    bool
	LockUntil time.Time
}

func NewSecureAuthService(db *sql.DB, logger *log.Logger) *SecureAuthService {
	return &SecureAuthService{
		db:     db,
		logger: logger,
		config: MFAConfig{
			MaxPushAttemptsPerHour:    3,  // Anti-fatigue: limit push notifications
			MaxTOTPAttemptsPerSession: 5,  // Lock after 5 failed TOTP attempts
			BackupCodeCount:           10, // Generate 10 backup codes
			PartialSessionTTL:         5 * time.Minute,
			PushCooldownPeriod:        2 * time.Minute, // Minimum time between pushes
		},
	}
}

// Anti-MFA-Fatigue: Rate limit push notifications per user
func (s *SecureAuthService) checkPushRateLimit(userID int) (bool, string) {
	key := fmt.Sprintf("push_limit_%d", userID)
	val, exists := s.rateLimits.Load(key)

	if !exists {
		s.rateLimits.Store(key, &MFAAttempt{Count: 1, LastReset: time.Now()})
		return true, ""
	}

	attempt := val.(*MFAAttempt)

	// Reset counter after 1 hour
	if time.Since(attempt.LastReset) > time.Hour {
		attempt.Count = 1
		attempt.LastReset = time.Now()
		attempt.Locked = false
		return true, ""
	}

	if attempt.Locked && time.Now().Before(attempt.LockUntil) {
		return false, "Too many push notifications. Account temporarily locked. Use TOTP or backup code."
	}

	if attempt.Count >= s.config.MaxPushAttemptsPerHour {
		attempt.Locked = true
		attempt.LockUntil = time.Now().Add(time.Hour)
		s.logger.Printf("SECURITY: MFA fatigue protection triggered for user %d", userID)
		return false, "Push notification limit reached. Use authenticator app or backup code."
	}

	attempt.Count++
	return true, ""
}

// Generate cryptographically secure backup codes
func (s *SecureAuthService) GenerateBackupCodes(userID int) ([]string, error) {
	var codes []string
	var hashedCodes []string

	for i := 0; i < s.config.BackupCodeCount; i++ {
		// Generate 8-character alphanumeric code
		bytes := make([]byte, 6)
		if _, err := rand.Read(bytes); err != nil {
			return nil, err
		}
		code := strings.ToUpper(base32.StdEncoding.EncodeToString(bytes))[:8]
		codes = append(codes, code)

		// Store hashed version only
		hash := sha256.Sum256([]byte(code))
		hashedCodes = append(hashedCodes, hex.EncodeToString(hash[:]))
	}

	// Delete old backup codes and insert new ones
	tx, err := s.db.Begin()
	if err != nil {
		return nil, err
	}
	defer tx.Rollback()

	_, err = tx.Exec("DELETE FROM backup_codes WHERE user_id = $1", userID)
	if err != nil {
		return nil, err
	}

	for _, hashedCode := range hashedCodes {
		_, err = tx.Exec(
			"INSERT INTO backup_codes (user_id, code_hash, used, created_at) VALUES ($1, $2, false, $3)",
			userID, hashedCode, time.Now(),
		)
		if err != nil {
			return nil, err
		}
	}

	if err := tx.Commit(); err != nil {
		return nil, err
	}

	s.logger.Printf("Generated %d new backup codes for user %d", len(codes), userID)
	return codes, nil // Return plaintext codes once for user to save
}

// Verify backup code (single-use)
func (s *SecureAuthService) verifyBackupCode(userID int, code string) bool {
	hash := sha256.Sum256([]byte(strings.ToUpper(code)))
	hashedCode := hex.EncodeToString(hash[:])

	tx, err := s.db.Begin()
	if err != nil {
		return false
	}
	defer tx.Rollback()

	var codeID int
	err = tx.QueryRow(
		"SELECT id FROM backup_codes WHERE user_id = $1 AND code_hash = $2 AND used = false",
		userID, hashedCode,
	).Scan(&codeID)

	if err != nil {
		s.logger.Printf("Backup code verification failed for user %d", userID)
		return false
	}

	// Mark code as used immediately (single-use)
	_, err = tx.Exec("UPDATE backup_codes SET used = true, used_at = $1 WHERE id = $2", time.Now(), codeID)
	if err != nil {
		return false
	}

	if err := tx.Commit(); err != nil {
		return false
	}

	// Alert user about backup code usage
	s.logger.Printf("SECURITY: Backup code used for user %d - consider regenerating codes", userID)
	return true
}

// Multi-method MFA verification handler
func (s *SecureAuthService) VerifyMFAHandler(w http.ResponseWriter, r *http.Request) {
	var req struct {
		SessionToken string    `json:"session_token"`
		MFAMethod    MFAMethod `json:"mfa_method"`
		Code         string    `json:"code"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate partial session
	var userID int
	var expiresAt time.Time
	var attempts int
	err := s.db.QueryRow(
		"SELECT user_id, expires_at, mfa_attempts FROM pending_mfa_sessions WHERE token = $1",
		req.SessionToken,
	).Scan(&userID, &expiresAt, &attempts)

	if err != nil || time.Now().After(expiresAt) {
		s.logger.Printf("SECURITY: Invalid/expired MFA session attempted")
		http.Error(w, "Session expired. Please login again.", http.StatusUnauthorized)
		return
	}

	// Check attempt limits (anti-brute-force)
	if attempts >= s.config.MaxTOTPAttemptsPerSession {
		s.db.Exec("DELETE FROM pending_mfa_sessions WHERE token = $1", req.SessionToken)
		s.logger.Printf("SECURITY: MFA brute force detected for user %d, session invalidated", userID)
		http.Error(w, "Too many failed attempts. Please login again.", http.StatusTooManyRequests)
		return
	}

	var verified bool
	var methodUsed string

	switch req.MFAMethod {
	case MFATOTP:
		var totpSecret string
		s.db.QueryRow("SELECT totp_secret FROM users WHERE id = $1", userID).Scan(&totpSecret)
		verified = totp.Validate(req.Code, totpSecret)
		methodUsed = "TOTP"

	case MFABackupCode:
		verified = s.verifyBackupCode(userID, req.Code)
		methodUsed = "Backup Code"

	case MFAPush:
		// Check rate limit for push (anti-fatigue)
		allowed, message := s.checkPushRateLimit(userID)
		if !allowed {
			json.NewEncoder(w).Encode(map[string]interface{}{
				"status":  "push_limited",
				"message": message,
				"suggest": "Use TOTP or backup code instead",
			})
			return
		}
		// In production: send push notification and wait for approval
		// This is a placeholder - implement async push verification
		verified = false
		methodUsed = "Push"

	default:
		http.Error(w, "Invalid MFA method", http.StatusBadRequest)
		return
	}

	if !verified {
		// Increment attempt counter
		s.db.Exec(
			"UPDATE pending_mfa_sessions SET mfa_attempts = mfa_attempts + 1 WHERE token = $1",
			req.SessionToken,
		)
		s.logger.Printf("MFA verification failed for user %d via %s (attempt %d)", userID, methodUsed, attempts+1)
		http.Error(w, "Invalid MFA code", http.StatusUnauthorized)
		return
	}

	// MFA verified - issue full session
	s.db.Exec("DELETE FROM pending_mfa_sessions WHERE token = $1", req.SessionToken)

	fullToken := s.generateSecureToken()
	expiresAt = time.Now().Add(24 * time.Hour)

	_, err = s.db.Exec(
		"INSERT INTO sessions (token, user_id, created_at, expires_at, mfa_method) VALUES ($1, $2, $3, $4, $5)",
		fullToken, userID, time.Now(), expiresAt, methodUsed,
	)

	s.logger.Printf("Full session issued for user %d via %s from IP %s", userID, methodUsed, r.RemoteAddr)

	// Send security notification for backup code usage
	if req.MFAMethod == MFABackupCode {
		go s.sendSecurityAlert(userID, "Backup code used for login. Consider regenerating codes.")
	}

	json.NewEncoder(w).Encode(map[string]interface{}{
		"status":     "authenticated",
		"token":      fullToken,
		"expires_at": expiresAt,
	})
}

func (s *SecureAuthService) generateSecureToken() string {
	bytes := make([]byte, 32)
	rand.Read(bytes)
	return hex.EncodeToString(bytes)
}

func (s *SecureAuthService) sendSecurityAlert(userID int, message string) {
	// Implementation: send email/SMS notification
	s.logger.Printf("Security alert for user %d: %s", userID, message)
}
