<?php
require_once 'config.php';
require_once 'vendor/autoload.php';

use Predis\Client as RedisClient;

class SecureAuthController {
    private PDO $pdo;
    private RedisClient $redis;
    private const MAX_ATTEMPTS_PER_IP = 10;
    private const MAX_ATTEMPTS_PER_USER = 5;
    private const LOCKOUT_DURATION = 900; // 15 minutes
    private const RATE_LIMIT_WINDOW = 300; // 5 minutes

    public function __construct(PDO $pdo, RedisClient $redis) {
        $this->pdo = $pdo;
        $this->redis = $redis;
    }

    public function login(string $username, string $password, string $clientIp): array {
