            $this->logSecurityEvent('rate_limit_ip', $username, $clientIp);
            return ['success' => false, 'message' => 'Too many attempts. Please try again later.', 'retry_after' => self::LOCKOUT_DURATION];
        }

        // DEFENSE 2: Account lockout check
        if ($this->isAccountLocked($username)) {
            $this->logSecurityEvent('locked_account_attempt', $username, $clientIp);
            return ['success' => false, 'message' => 'Account temporarily locked. Please try again later or reset your password.'];
        }

        // Fetch user
        $stmt = $this->pdo->prepare(
            "SELECT id, username, password_hash, email, failed_attempts, locked_until FROM users WHERE username = ?"
        );
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            // DEFENSE 3: Check if password is in known breach database
            if ($this->isPasswordCompromised($password)) {
                $this->forcePasswordReset($user['id']);
                $this->logSecurityEvent('compromised_password_login', $username, $clientIp);
                return ['success' => false, 'message' => 'Password found in data breach. Please reset your password.', 'require_reset' => true];
            }

            // Reset failed attempts on success
            $this->resetFailedAttempts($user['id']);
            $this->clearRateLimits($username, $clientIp);

            // Start secure session
            session_regenerate_id(true);
            $_SESSION['user_id'] = $user['id'];
            $_SESSION['username'] = $user['username'];
            $_SESSION['login_time'] = time();
            $_SESSION['ip_address'] = $clientIp;

            $this->logSecurityEvent('successful_login', $username, $clientIp);
            $this->notifyNewLogin($user, $clientIp);

            return ['success' => true, 'message' => 'Login successful'];
        }

        // Increment failure counters
        $this->incrementFailedAttempts($username, $clientIp);
        $this->logSecurityEvent('failed_login', $username, $clientIp);

        return ['success' => false, 'message' => 'Invalid credentials'];
    }

    private function isIpRateLimited(string $ip): bool {
        $key = "rate_limit:ip:{$ip}";
        $attempts = (int) $this->redis->get($key);
        return $attempts >= self::MAX_ATTEMPTS_PER_IP;
    }

    private function isAccountLocked(string $username): bool {
        $key = "account_locked:{$username}";
        return (bool) $this->redis->exists($key);
    }

    private function isPasswordCompromised(string $password): bool {
        // Use k-anonymity with Have I Been Pwned API
        $sha1 = strtoupper(sha1($password));
        $prefix = substr($sha1, 0, 5);
        $suffix = substr($sha1, 5);

        $ch = curl_init("https://api.pwnedpasswords.com/range/{$prefix}");
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, ['Add-Padding: true']);
        $response = curl_exec($ch);
        curl_close($ch);

        return str_contains($response, $suffix);
    }

    private function incrementFailedAttempts(string $username, string $ip): void {
        // Increment IP counter
        $ipKey = "rate_limit:ip:{$ip}";
        $this->redis->incr($ipKey);
        $this->redis->expire($ipKey, self::RATE_LIMIT_WINDOW);

        // Increment user counter and potentially lock account
        $userKey = "failed_attempts:{$username}";
        $attempts = $this->redis->incr($userKey);
        $this->redis->expire($userKey, self::RATE_LIMIT_WINDOW);

        if ($attempts >= self::MAX_ATTEMPTS_PER_USER) {
            $lockKey = "account_locked:{$username}";
            $this->redis->setex($lockKey, self::LOCKOUT_DURATION, '1');
        }
    }

    private function logSecurityEvent(string $event, string $username, string $ip): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO security_audit_log (event_type, username, ip_address, user_agent, created_at) VALUES (?, ?, ?, ?, NOW())"
        );
        $stmt->execute([$event, $username, $ip, $_SERVER['HTTP_USER_AGENT'] ?? '']);
    }

    private function resetFailedAttempts(int $userId): void {
        $stmt = $this->pdo->prepare("UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = ?");
        $stmt->execute([$userId]);
    }

    private function clearRateLimits(string $username, string $ip): void {
        $this->redis->del("rate_limit:ip:{$ip}");
        $this->redis->del("failed_attempts:{$username}");
        $this->redis->del("account_locked:{$username}");
    }

    private function forcePasswordReset(int $userId): void {
        $stmt = $this->pdo->prepare("UPDATE users SET password_reset_required = 1 WHERE id = ?");
        $stmt->execute([$userId]);
    }

    private function notifyNewLogin(array $user, string $ip): void {
        // Send email notification for login from new location
        // Implementation depends on email service
    }
}
