using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Identity;
using Microsoft.Extensions.Logging;
using Fido2NetLib;
using OtpNet;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SecureAuthController : ControllerBase
    {
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly ILogger<SecureAuthController> _logger;
        private readonly IFido2 _fido2;
        private readonly IMfaService _mfaService;
        private readonly IRiskEngine _riskEngine;
        private readonly IAuditService _auditService;
        private readonly IRateLimiter _rateLimiter;

        public SecureAuthController(
            UserManager<ApplicationUser> userManager,
            ILogger<SecureAuthController> logger,
            IFido2 fido2,
            IMfaService mfaService,
            IRiskEngine riskEngine,
            IAuditService auditService,
            IRateLimiter rateLimiter)
        {
            _userManager = userManager;
            _logger = logger;
            _fido2 = fido2;
            _mfaService = mfaService;
            _riskEngine = riskEngine;
            _auditService = auditService;
            _rateLimiter = rateLimiter;
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest request)
        {
            var clientIp = GetClientIp();

            // Rate limiting by IP and username
            if (!await _rateLimiter.AllowRequestAsync($"login:{clientIp}", 10, TimeSpan.FromMinutes(15)))
            {
                await _auditService.LogAsync(AuditEvent.RateLimitExceeded, clientIp);
                return StatusCode(429, "Too many attempts. Please try again later.");
            }

            var user = await _userManager.FindByEmailAsync(request.Email);
            if (user == null)
            {
                await Task.Delay(Random.Shared.Next(200, 600));
                await _auditService.LogAsync(AuditEvent.LoginFailedUnknownUser, 
                    request.Email, clientIp);
                return Unauthorized("Invalid credentials");
            }

            // Verify password first
            if (!await _userManager.CheckPasswordAsync(user, request.Password))
            {
                await _userManager.AccessFailedAsync(user);
                await _auditService.LogAsync(AuditEvent.LoginFailedBadPassword, 
                    user.Id, clientIp);

                if (await _userManager.IsLockedOutAsync(user))
                {
                    await _auditService.LogAsync(AuditEvent.AccountLockedOut, user.Id);
                    return StatusCode(423, "Account locked due to multiple failed attempts");
                }
                return Unauthorized("Invalid credentials");
            }

            // Reset failed attempts on successful password
            await _userManager.ResetAccessFailedCountAsync(user);

            // Risk-based authentication assessment
            var riskScore = await _riskEngine.EvaluateLoginRiskAsync(new RiskContext
            {
                UserId = user.Id,
                IpAddress = clientIp,
                UserAgent = Request.Headers["User-Agent"].ToString(),
                GeoLocation = await GetGeoLocationAsync(clientIp),
                DeviceFingerprint = request.DeviceFingerprint,
                LoginTime = DateTime.UtcNow
            });

            // Get available MFA methods for user
            var mfaMethods = await _mfaService.GetEnabledMethodsAsync(user.Id);

            // Determine required authentication level
            var requiredMfaLevel = DetermineRequiredMfaLevel(user, riskScore, mfaMethods);

            if (requiredMfaLevel == MfaLevel.None && riskScore < 0.3)
            {
                // Low risk, basic user - allow login but encourage MFA
                var token = await GenerateSecureTokenAsync(user, MfaLevel.None);
                await _auditService.LogAsync(AuditEvent.LoginSuccess, user.Id, clientIp);
                return Ok(new { Token = token, MfaRecommended = true });
            }

            // Create secure MFA challenge session
            var challengeSession = await _mfaService.CreateChallengeSessionAsync(
                user.Id, mfaMethods, requiredMfaLevel, TimeSpan.FromMinutes(5));

            await _auditService.LogAsync(AuditEvent.MfaChallengeIssued, 
                user.Id, clientIp, requiredMfaLevel.ToString());

            return Ok(new
            {
                RequiresMfa = true,
                ChallengeId = challengeSession.Id,
                AvailableMethods = mfaMethods.Select(m => new
                {
                    Type = m.Type.ToString(),
                    Hint = m.GetMaskedHint() // e.g., "***-***-1234" for SMS
                }),
                PreferredMethod = user.PreferredMfaMethod?.ToString(),
                ExpiresIn = 300
            });
        }

        [HttpPost("verify-totp")]
        public async Task<IActionResult> VerifyTotp([FromBody] TotpVerifyRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired. Please login again.");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var totpSecret = await _mfaService.GetTotpSecretAsync(user.Id);

            // TOTP verification with replay protection
            var totp = new Totp(Base32Encoding.ToBytes(totpSecret));
            long timeStepMatched;
            var isValid = totp.VerifyTotp(
                request.Code, 
                out timeStepMatched, 
                VerificationWindow.RfcSpecifiedNetworkDelay);

            if (!isValid)
            {
                await _mfaService.IncrementFailedAttemptsAsync(challenge.Id);
                await _auditService.LogAsync(AuditEvent.MfaFailed, 
                    user.Id, "TOTP", GetClientIp());

                if (await _mfaService.IsChallengeLocked(challenge.Id))
                {
                    return StatusCode(423, "Too many failed attempts");
                }
                return Unauthorized("Invalid code");
            }

            // Replay protection - ensure code wasn't already used
            if (await _mfaService.IsCodeReplayedAsync(user.Id, timeStepMatched))
            {
                await _auditService.LogAsync(AuditEvent.MfaReplayAttempt, user.Id);
                return Unauthorized("Code already used");
            }
            await _mfaService.RecordCodeUseAsync(user.Id, timeStepMatched);

            return await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.Totp);
        }

        [HttpPost("verify-webauthn")]
        public async Task<IActionResult> VerifyWebAuthn([FromBody] WebAuthnVerifyRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var credentials = await _mfaService.GetWebAuthnCredentialsAsync(user.Id);

            // Verify FIDO2/WebAuthn assertion
            var options = await _fido2.GetAssertionOptionsAsync(
                credentials.Select(c => c.Descriptor).ToList(),
                UserVerificationRequirement.Required);

            var result = await _fido2.MakeAssertionAsync(
                request.AuthenticatorResponse,
                options,
                credentials.First(c => c.Id.SequenceEqual(request.CredentialId)).PublicKey,
                credentials.First(c => c.Id.SequenceEqual(request.CredentialId)).SignatureCounter,
                async (args, ct) =>
                {
                    var cred = credentials.FirstOrDefault(c => c.Id.SequenceEqual(args.CredentialId));
                    return cred != null;
                });

            if (result.Status != "ok")
            {
                await _auditService.LogAsync(AuditEvent.MfaFailed, user.Id, "WebAuthn");
                return Unauthorized("Hardware key verification failed");
            }

            // Update signature counter for cloning detection
            await _mfaService.UpdateSignatureCounterAsync(
                user.Id, request.CredentialId, result.Counter);

            return await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.WebAuthn);
        }

        [HttpPost("send-sms-code")]
        public async Task<IActionResult> SendSmsCode([FromBody] SmsSendRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired");
            }

            // Rate limit SMS sends (expensive and phishable)
            if (!await _rateLimiter.AllowRequestAsync(
                $"sms:{challenge.UserId}", 3, TimeSpan.FromHours(1)))
            {
                return StatusCode(429, "SMS limit exceeded");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var code = GenerateSecureSmsCode();

            await _mfaService.StoreSmsCodeAsync(challenge.Id, code, TimeSpan.FromMinutes(10));
            await _smsService.SendAsync(user.PhoneNumber, 
                $"Your verification code is: {code}. Valid for 10 minutes.");

            await _auditService.LogAsync(AuditEvent.SmsMfaCodeSent, user.Id);

            return Ok(new { Message = "Code sent", ExpiresIn = 600 });
        }

        [HttpPost("verify-sms")]
        public async Task<IActionResult> VerifySms([FromBody] SmsVerifyRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var storedCode = await _mfaService.GetSmsCodeAsync(challenge.Id);

            // Constant-time comparison to prevent timing attacks
            if (!CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(request.Code),
                Encoding.UTF8.GetBytes(storedCode ?? "")))
            {
                await _mfaService.IncrementFailedAttemptsAsync(challenge.Id);
                await _auditService.LogAsync(AuditEvent.MfaFailed, user.Id, "SMS");
                return Unauthorized("Invalid code");
            }

            // Invalidate code after use
            await _mfaService.InvalidateSmsCodeAsync(challenge.Id);

            return await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.Sms);
        }

        [HttpPost("use-backup-code")]
        public async Task<IActionResult> UseBackupCode([FromBody] BackupCodeRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);

            // Verify and consume backup code (one-time use)
            var isValid = await _mfaService.VerifyAndConsumeBackupCodeAsync(
                user.Id, request.Code);

            if (!isValid)
            {
                await _auditService.LogAsync(AuditEvent.MfaFailed, user.Id, "BackupCode");
                return Unauthorized("Invalid or already used backup code");
            }

            // Alert user about backup code usage
            await _notificationService.SendSecurityAlertAsync(user.Email,
                "A backup code was used to access your account",
                GetClientIp());

            var remainingCodes = await _mfaService.GetRemainingBackupCodeCountAsync(user.Id);

            await _auditService.LogAsync(AuditEvent.BackupCodeUsed, 
                user.Id, $"Remaining: {remainingCodes}");

            var result = await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.BackupCode);

            // Warn if running low on backup codes
            if (remainingCodes <= 2)
            {
                return Ok(new
                {
                    Token = ((OkObjectResult)result).Value,
                    Warning = $"Only {remainingCodes} backup codes remaining. Please generate new codes."
                });
            }

            return result;
        }

        private async Task<IActionResult> CompleteMfaVerificationAsync(
            ApplicationUser user, 
            MfaChallengeSession challenge,
            MfaMethodType method)
        {
            await _mfaService.CompleteChallengeAsync(challenge.Id);

            var mfaLevel = GetMfaLevelForMethod(method);
            var token = await GenerateSecureTokenAsync(user, mfaLevel);

            await _auditService.LogAsync(AuditEvent.LoginSuccess, 
                user.Id, GetClientIp(), $"MFA:{method}");

            // Update last login and security context
            user.LastLoginAt = DateTime.UtcNow;
            user.LastLoginIp = GetClientIp();
            user.LastMfaMethod = method;
            await _userManager.UpdateAsync(user);

            return Ok(new
            {
                Token = token,
                ExpiresIn = 3600,
                MfaMethod = method.ToString()
            });
        }

        private MfaLevel DetermineRequiredMfaLevel(
            ApplicationUser user, 
            double riskScore,
            List<MfaMethod> availableMethods)
        {
            // Always require MFA for privileged roles
            if (user.Roles.Any(r => r.Name is "Admin" or "Finance" or "Security"))
            {
                return MfaLevel.Required;
            }

            // High risk score triggers step-up authentication
            if (riskScore > 0.7)
            {
                return availableMethods.Any(m => m.Type == MfaMethodType.WebAuthn)
                    ? MfaLevel.PhishingResistant
                    : MfaLevel.Required;
            }

            // Medium risk requires standard MFA
            if (riskScore > 0.4)
            {
                return MfaLevel.Required;
            }

            // User has MFA enabled - use it
            if (availableMethods.Any())
            {
                return MfaLevel.Optional;
            }

            return MfaLevel.None;
        }

        private string GenerateSecureSmsCode()
        {
            using var rng = RandomNumberGenerator.Create();
            var bytes = new byte[4];
            rng.GetBytes(bytes);
            var code = (BitConverter.ToUInt32(bytes, 0) % 900000) + 100000;
            return code.ToString();
        }
    }
}
