```java
import java.sql.*;
import java.security.SecureRandom;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import dev.samstevens.totp.code.*;
import dev.samstevens.totp.time.SystemTimeProvider;

public class SecureLoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    private final CodeVerifier totpVerifier;

    public SecureLoginServlet() {
        this.totpVerifier = new DefaultCodeVerifier(
            new DefaultCodeGenerator(),
            new SystemTimeProvider()
        );
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String totpCode = request.getParameter("totp_code");

        // Input validation
        if (username == null || password == null || totpCode == null ||
            username.length() > 50 || password.length() > 128 || !totpCode.matches("\\d{6}")) {
            logFailedAttempt(request, username, "INVALID_INPUT");
            response.sendRedirect("/login?error=invalid");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT id, password_hash, totp_secret, failed_attempts, locked_until FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                // Check account lockout
                Timestamp lockedUntil = rs.getTimestamp("locked_until");
                if (lockedUntil != null && lockedUntil.after(new Timestamp(System.currentTimeMillis()))) {
                    logFailedAttempt(request, username, "ACCOUNT_LOCKED");
                    response.sendRedirect("/login?error=locked");
                    return;
                }

                String storedHash = rs.getString("password_hash");
                String totpSecret = rs.getString("totp_secret");
                int userId = rs.getInt("id");

                // Step 1: Verify password
                if (BCrypt.checkpw(password, storedHash)) {
                    // Step 2: MANDATORY MFA verification
                    if (totpVerifier.isValidCode(totpSecret, totpCode)) {
                        // Both factors verified - create session
                        resetFailedAttempts(conn, userId);
                        HttpSession session = request.getSession(true);
                        session.setAttribute("authenticated", true);
                        session.setAttribute("user_id", userId);
                        session.setAttribute("mfa_verified", true);
                        session.setMaxInactiveInterval(1800); // 30 minutes

                        logSuccessfulLogin(request, username);
                        response.sendRedirect("/dashboard");
                        return;
                    }
                }
                incrementFailedAttempts(conn, userId);
            }

            // Use constant-time response to prevent user enumeration
            Thread.sleep(100 + new SecureRandom().nextInt(100));
            logFailedAttempt(request, username, "INVALID_CREDENTIALS");
            response.sendRedirect("/login?error=invalid");

        } catch (Exception e) {
            logError("Login error", e);
            response.sendRedirect("/login?error=system");
        }
    }

    private void logFailedAttempt(HttpServletRequest req, String username, String reason) {
        System.out.println(String.format("AUTH_FAIL: user=%s ip=%s reason=%s", 
            username, req.getRemoteAddr(), reason));
    }

    private void logSuccessfulLogin(HttpServletRequest req, String username) {
        System.out.println(String.format("AUTH_SUCCESS: user=%s ip=%s", 
            username, req.getRemoteAddr()));
    }
}
```

**Key Security Controls**:
- **TOTP-based MFA**: Time-based one-time passwords that expire every 30 seconds, impossible to reuse or phish effectively
- **Account lockout**: Prevents brute force attacks on both password and TOTP codes
- **Constant-time responses**: Random delay prevents timing attacks that enumerate valid usernames
- **Session security**: Short timeout, proper session management with MFA verification flag

Excellent question - MFA recovery is often where security breaks down. Many organizations implement 'forgot MFA' flows that essentially bypass MFA entirely, defeating its purpose. The 2023 Retool breach occurred when attackers social-engineered IT support to reset MFA for a targeted employee.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import dev.samstevens.totp.code.*;
import dev.samstevens.totp.secret.DefaultSecretGenerator;

public class SecureMFARecoveryService {

    private static final int BACKUP_CODE_COUNT = 10;
    private static final int RECOVERY_COOLDOWN_HOURS = 24;
    private static final String DB_URL = System.getenv("DB_URL");

    private final CodeVerifier totpVerifier;
    private final SecureRandom secureRandom;
    private final NotificationService notificationService;
    private final AuditLogger auditLogger;

    public SecureMFARecoveryService(NotificationService notificationService, AuditLogger auditLogger) {
        this.totpVerifier = new DefaultCodeVerifier(
            new DefaultCodeGenerator(),
            new SystemTimeProvider()
        );
        this.secureRandom = new SecureRandom();
        this.notificationService = notificationService;
        this.auditLogger = auditLogger;
    }

    /**
     * Generate backup codes during MFA enrollment - ONLY shown once
     */
    public List<String> generateBackupCodes(int userId, Connection conn) throws SQLException {
        List<String> plainCodes = new ArrayList<>();
        List<String> hashedCodes = new ArrayList<>();

        // Generate cryptographically secure backup codes
        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            // Format: XXXX-XXXX-XXXX (12 alphanumeric chars)
            String code = generateSecureCode();
            plainCodes.add(code);
            hashedCodes.add(BCrypt.hashpw(code, BCrypt.gensalt(12)));
        }

        // Store hashed codes - never store plaintext!
        String sql = "DELETE FROM backup_codes WHERE user_id = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, userId);
            stmt.executeUpdate();
        }

        sql = "INSERT INTO backup_codes (user_id, code_hash, created_at) VALUES (?, ?, NOW())";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            for (String hashedCode : hashedCodes) {
                stmt.setInt(1, userId);
                stmt.setString(2, hashedCode);
                stmt.addBatch();
            }
            stmt.executeBatch();
        }

        auditLogger.log("BACKUP_CODES_GENERATED", userId, 
            Map.of("count", BACKUP_CODE_COUNT));

        // Return plaintext codes to show user ONCE
        return plainCodes;
    }

    /**
     * Authenticate using a backup code - one-time use
     */
    public boolean authenticateWithBackupCode(int userId, String providedCode, 
                                               Connection conn, HttpServletRequest request) 
                                               throws SQLException {

        // Rate limit backup code attempts
        if (isRateLimited(userId, "backup_code", conn)) {
            auditLogger.log("BACKUP_CODE_RATE_LIMITED", userId,
                Map.of("ip", request.getRemoteAddr()));
            return false;
        }

        String sql = "SELECT id, code_hash FROM backup_codes WHERE user_id = ? AND used_at IS NULL";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, userId);
            ResultSet rs = stmt.executeQuery();

            while (rs.next()) {
                int codeId = rs.getInt("id");
                String storedHash = rs.getString("code_hash");

                if (BCrypt.checkpw(providedCode.replace("-", ""), storedHash)) {
                    // Mark code as used - one-time only!
                    markBackupCodeUsed(codeId, conn);

                    // Count remaining codes and warn if low
                    int remaining = countRemainingBackupCodes(userId, conn);
                    if (remaining <= 3) {
                        notificationService.sendLowBackupCodesWarning(userId, remaining);
                    }

                    auditLogger.log("BACKUP_CODE_USED", userId,
                        Map.of("ip", request.getRemoteAddr(), 
                               "remaining_codes", remaining));

                    // Notify all registered devices about recovery login
                    notificationService.sendSecurityAlert(userId,
                        "Login with backup code from IP: " + request.getRemoteAddr());

                    return true;
                }
            }
        }

        recordFailedAttempt(userId, "backup_code", conn);
        auditLogger.log("BACKUP_CODE_FAILED", userId,
            Map.of("ip", request.getRemoteAddr()));
        return false;
    }

    /**
     * Initiate MFA reset - requires identity verification
     */
    public String initiateMFARecovery(int userId, Connection conn, 
                                       HttpServletRequest request) throws SQLException {

        // Check for recent recovery attempts (prevent abuse)
        if (hasRecentRecoveryAttempt(userId, conn)) {
            auditLogger.log("MFA_RECOVERY_COOLDOWN", userId,
                Map.of("ip", request.getRemoteAddr()));
            throw new SecurityException("Recovery recently initiated. Please wait 24 hours.");
        }

        // Generate secure recovery token
        byte[] tokenBytes = new byte[32];
        secureRandom.nextBytes(tokenBytes);
        String recoveryToken = Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
        String tokenHash = BCrypt.hashpw(recoveryToken, BCrypt.gensalt(12));

        // Store recovery request with expiration
        String sql = "INSERT INTO mfa_recovery_requests " +
                     "(user_id, token_hash, created_at, expires_at, ip_address, user_agent, status) " +
                     "VALUES (?, ?, NOW(), NOW() + INTERVAL '1 hour', ?, ?, 'PENDING')";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, userId);
            stmt.setString(2, tokenHash);
            stmt.setString(3, request.getRemoteAddr());
            stmt.setString(4, request.getHeader("User-Agent"));
            stmt.executeUpdate();
        }

        // Notify user via ALL registered channels (email, SMS, push)
        notificationService.sendMFARecoveryInitiated(userId, request.getRemoteAddr());

        auditLogger.log("MFA_RECOVERY_INITIATED", userId,
            Map.of("ip", request.getRemoteAddr()));

        // Token sent via verified email - never returned in API response
        notificationService.sendMFARecoveryLink(userId, recoveryToken);

        return "Recovery instructions sent to your verified email.";
    }

    /**
     * Complete MFA recovery with enhanced verification
     */
    public MFAEnrollmentResult completeMFARecovery(String recoveryToken, 
                                                    String newTotpCode,
                                                    IdentityVerification verification,
                                                    Connection conn,
                                                    HttpServletRequest request) 
                                                    throws SQLException {

        // Find valid, unexpired recovery request
        String sql = "SELECT id, user_id, ip_address FROM mfa_recovery_requests " +
                     "WHERE status = 'PENDING' AND expires_at > NOW()";

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            ResultSet rs = stmt.executeQuery();

            while (rs.next()) {
                int requestId = rs.getInt("id");
                int userId = rs.getInt("user_id");
                String originalIp = rs.getString("ip_address");

                // Verify token (stored hashed)
                // Note: In production, you'd need to retrieve and verify the hash

                // STEP 1: Verify additional identity factors
                if (!verifyIdentity(userId, verification, conn)) {
                    markRecoveryFailed(requestId, conn, "IDENTITY_VERIFICATION_FAILED");
                    auditLogger.log("MFA_RECOVERY_IDENTITY_FAILED", userId,
                        Map.of("ip", request.getRemoteAddr()));
                    throw new SecurityException("Identity verification failed");
                }

                // STEP 2: Generate new TOTP secret
                String newSecret = new DefaultSecretGenerator().generate();

                // STEP 3: Verify user can generate valid codes
                if (!totpVerifier.isValidCode(newSecret, newTotpCode)) {
                    throw new IllegalArgumentException("Invalid TOTP code for new secret");
                }

                // STEP 4: Update user's MFA secret
                String updateSql = "UPDATE users SET totp_secret = ?, mfa_updated_at = NOW() WHERE id = ?";
                try (PreparedStatement updateStmt = conn.prepareStatement(updateSql)) {
                    updateStmt.setString(1, newSecret);
                    updateStmt.setInt(2, userId);
                    updateStmt.executeUpdate();
                }

                // STEP 5: Invalidate all existing sessions
                invalidateAllSessions(userId, conn);

                // STEP 6: Generate new backup codes
                List<String> newBackupCodes = generateBackupCodes(userId, conn);

                // Mark recovery complete
                markRecoveryComplete(requestId, conn);

                // Alert on all channels
                notificationService.sendMFAResetComplete(userId, request.getRemoteAddr());

                auditLogger.log("MFA_RECOVERY_COMPLETE", userId,
                    Map.of("ip", request.getRemoteAddr(), 
                           "original_ip", originalIp,
                           "sessions_invalidated", true));

                // Enforce 24-hour waiting period for sensitive actions
                setSecurityHold(userId, conn, 24);

                return new MFAEnrollmentResult(newSecret, newBackupCodes);
            }
        }

        throw new SecurityException("Invalid or expired recovery request");
    }

    /**
     * Verify identity through multiple factors
     */
    private boolean verifyIdentity(int userId, IdentityVerification verification, 
                                    Connection conn) throws SQLException {
        int verifiedFactors = 0;
        int requiredFactors = 2;  // Require at least 2 alternative factors

        // Factor 1: Email verification code
        if (verification.getEmailCode() != null) {
            if (verifyEmailCode(userId, verification.getEmailCode(), conn)) {
                verifiedFactors++;
            }
        }

        // Factor 2: SMS verification code (different channel)
        if (verification.getSmsCode() != null) {
            if (verifySmsCode(userId, verification.getSmsCode(), conn)) {
                verifiedFactors++;
            }
        }

        // Factor 3: Security questions (knowledge-based)
        if (verification.getSecurityAnswers() != null) {
            if (verifySecurityQuestions(userId, verification.getSecurityAnswers(), conn)) {
                verifiedFactors++;
            }
        }

        // Factor 4: Government ID verification (for high-security accounts)
        if (verification.getIdVerificationToken() != null) {
            if (verifyGovernmentId(userId, verification.getIdVerificationToken())) {
                verifiedFactors += 2;  // Worth more
            }
        }

        return verifiedFactors >= requiredFactors;
    }

    private String generateSecureCode() {
        String chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";  // Exclude confusing chars
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < 12; i++) {
            if (i > 0 && i % 4 == 0) code.append("-");
            code.append(chars.charAt(secureRandom.nextInt(chars.length())));
        }
        return code.toString();
    }

